task automatic program_sign_inputs(input integer run);
    begin
        for (word_idx = 0; word_idx < SEED_WORDS;
             word_idx = word_idx + 1) begin
            DUT.key_sign_mem_inst.mem[`SK_SEED_ADDR + word_idx]
                = seed_sk[run][word_idx];
            DUT.key_sign_mem_inst.mem[`PK_SEED_ADDR + word_idx]
                = seed_pk[run][word_idx];
        end
        for (word_idx = 0; word_idx < SALT_WORDS;
             word_idx = word_idx + 1) begin
            DUT.key_sign_mem_inst.mem[`SALT_ADDR + word_idx]
                = salt[run][word_idx];
        end
        for (word_idx = 0; word_idx < MESSAGE_WORDS;
             word_idx = word_idx + 1) begin
            DUT.key_sign_mem_inst.mem[`MSG_ADDR + word_idx]
                = message[run][word_idx];
        end
        for (word_idx = 0; word_idx < ROOT_WORDS;
             word_idx = word_idx + 1) begin
            DUT.data_mem_inst.ram[`ROOT_SEED_ADDR + word_idx]
                = root_seed[run][word_idx];
        end
    end
endtask

task automatic check_sign_outputs(input integer run);
    begin
        for (word_idx = 0; word_idx < Y_WORDS;
             word_idx = word_idx + 1) begin
            if (DUT.key_sign_mem_inst.mem[`Y_ADDR + word_idx]
                    !== expected_y[run][word_idx]) begin
                $fatal(1,
                    "Run %0d SIGN y[%0d] wrong: got %016h, expected %016h",
                    run, word_idx,
                    DUT.key_sign_mem_inst.mem[`Y_ADDR + word_idx],
                    expected_y[run][word_idx]);
            end
        end
        for (word_idx = 0; word_idx < HASH_WORDS;
             word_idx = word_idx + 1) begin
            if (DUT.key_sign_mem_inst.mem[`HASH_SH_ADDR + word_idx]
                    !== expected_hash_sh[run][word_idx]) begin
                $fatal(1,
                    "Run %0d SIGN hash_sh[%0d] wrong: got %016h, expected %016h",
                    run, word_idx,
                    DUT.key_sign_mem_inst.mem[`HASH_SH_ADDR + word_idx],
                    expected_hash_sh[run][word_idx]);
            end
            if (DUT.key_sign_mem_inst.mem[`H_MPC_ADDR + word_idx]
                    !== expected_hash_mpc[run][word_idx]) begin
                $fatal(1,
                    "Run %0d SIGN hash_mpc[%0d] wrong: got %016h, expected %016h",
                    run, word_idx,
                    DUT.key_sign_mem_inst.mem[`H_MPC_ADDR + word_idx],
                    expected_hash_mpc[run][word_idx]);
            end
        end
        if (DUT.key_sign_mem_inst.mem[`H_MPC_ADDR + `COMMIT_WORDS]
                !== expected_ctr[run]) begin
            $fatal(1,
                "Run %0d SIGN ctr wrong: got %016h, expected %016h",
                run,
                DUT.key_sign_mem_inst.mem[`H_MPC_ADDR + `COMMIT_WORDS],
                expected_ctr[run]);
        end
    end
endtask

